namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {

Config::Config(const ProtoConfig& proto_config) {
  for (const auto& header : proto_config.request_headers_to_inject()) {
    request_headers_to_inject_.push_back(header);
  }
  for (const auto& header : proto_config.response_headers_to_inject()) {
    response_headers_to_inject_.push_back(header);
  }
}

CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    : config_(config) {}

CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
  const auto* config = getConfig();
  injectHeaders(headers, config->requestHeadersToInject());
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    Http::StreamDecoderFilterCallbacks& callbacks) {
  decoder_callbacks_ = &callbacks;
}

Http::FilterHeadersStatus
CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
  const auto* config = getConfig();
  injectHeaders(headers, config->responseHeadersToInject());
  return Http::FilterHeadersStatus::Continue;
}

void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    Http::StreamEncoderFilterCallbacks& callbacks) {
  encoder_callbacks_ = &callbacks;
}

void CustomHeaderInjectionFilter::injectHeaders(
    Http::HeaderMap& headers, const std::vector<ProtoHeaderValue>& headers_to_inject) {
  for (const auto& header_value : headers_to_inject) {
    headers.setCopy(Http::LowerCaseString(header_value.header_name()), header_value.header_value());
  }
}

const Config* CustomHeaderInjectionFilter::getConfig() const {
  // Cached config pointer.
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ =
      Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
  if (effective_config_) {
    return effective_config_;
  }

  effective_config_ = config_.get();
  return effective_config_;
}

